fn convert_base(n: i64, b: i64) -> String = {
    if n == 0 { return "0" };

    let mut num = n;
    let mut result = "";

    while num > 0 {
        let digit = num % b;
        let digit_str = to_string(digit);
        result = digit_str + result;
        num = num / b
    };

    result
};

